<?php
namespace Tests\Feature;use App\Jobs\DetectMissingDailyReportsJob;use App\Models\{DailyReport,MissingDailyReport,Task,TaskApproval,User,WorkProof,Workspace,WorkspaceSetting};use App\Support\CurrentWorkspace;use Illuminate\Foundation\Testing\RefreshDatabase;use Illuminate\Http\UploadedFile;use Illuminate\Support\Facades\Storage;use Tests\TestCase;
class Phase3AccountabilityTest extends TestCase{use RefreshDatabase;private function member(string $role='staff'):array{$u=User::create(['name'=>fake()->name(),'email'=>fake()->unique()->safeEmail(),'password'=>'password','status'=>'active']);$w=Workspace::create(['uuid'=>(string)str()->uuid(),'name'=>'Acme','slug'=>'acme'.uniqid(),'status'=>'active','owner_id'=>$u->id,'edition'=>'saas']);$w->users()->attach($u->id,['role_key'=>$role,'status'=>'active','joined_at'=>now()]);WorkspaceSetting::create(['workspace_id'=>$w->id,'daily_report_required'=>true,'daily_report_deadline'=>'00:01:00','working_days'=>[strtolower(now()->englishDayOfWeek)]]);app(CurrentWorkspace::class)->set($w);return[$u,$w];}private function asTenant($u,$w){app(CurrentWorkspace::class)->set($w);return $this->actingAs($u)->withSession(['current_workspace_id'=>$w->id]);}public function test_staff_can_create_and_submit_daily_report_and_duplicate_is_blocked():void{[$u,$w]=$this->member();$this->asTenant($u,$w)->post('/daily-reports',['report_date'=>today()->toDateString(),'completed_summary'=>'Done'])->assertRedirect();$report=DailyReport::first();$this->asTenant($u,$w)->post('/daily-reports',['report_date'=>today()->toDateString()])->assertSessionHasErrors('report_date');$this->asTenant($u,$w)->post("/daily-reports/{$report->id}/submit")->assertRedirect();$this->assertDatabaseHas('daily_reports',['id'=>$report->id,'status'=>'submitted','is_late'=>true]);}public function test_manager_can_approve_and_reject_daily_reports():void{[$m,$w]=$this->member('manager');$staff=User::create(['name'=>'Staff','email'=>'staff@example.com','password'=>'x','status'=>'active']);$w->users()->attach($staff->id,['role_key'=>'staff','status'=>'active']);$report=DailyReport::create(['workspace_id'=>$w->id,'user_id'=>$staff->id,'report_date'=>today(),'status'=>'submitted']);$this->asTenant($m,$w)->post("/daily-reports/{$report->id}/approve",['quality_score'=>8])->assertRedirect();$this->assertDatabaseHas('daily_reports',['id'=>$report->id,'status'=>'approved','quality_score'=>8]);$report->update(['status'=>'submitted']);$this->asTenant($m,$w)->post("/daily-reports/{$report->id}/reject",['review_comment'=>'Clarify'])->assertRedirect();$this->assertDatabaseHas('daily_reports',['id'=>$report->id,'status'=>'rejected','review_comment'=>'Clarify']);}public function test_proof_and_task_approval_workflow():void{Storage::fake('local');[$u,$w]=$this->member('staff');$task=Task::create(['workspace_id'=>$w->id,'title'=>'Proof task','priority'=>'medium','status'=>'new','proof_required'=>true,'approval_required'=>true]);$this->asTenant($u,$w)->post("/tasks/{$task->id}/request-approval")->assertSessionHasErrors('proof');$this->asTenant($u,$w)->post("/tasks/{$task->id}/proofs",['proof_type'=>'file','file'=>UploadedFile::fake()->create('proof.pdf',1)])->assertRedirect();$proof=WorkProof::first();$this->assertStringContainsString("workspaces/{$w->id}/tasks/{$task->id}/proofs",$proof->file_path);$this->asTenant($u,$w)->post("/tasks/{$task->id}/request-approval")->assertRedirect();$this->assertDatabaseHas('tasks',['id'=>$task->id,'status'=>'review']);$manager=User::create(['name'=>'Mgr','email'=>'mgr@example.com','password'=>'x','status'=>'active']);$w->users()->attach($manager->id,['role_key'=>'manager','status'=>'active']);$approval=TaskApproval::first();$this->asTenant($manager,$w)->post("/proofs/{$proof->id}/approve")->assertRedirect();$this->assertDatabaseHas('work_proofs',['id'=>$proof->id,'status'=>'approved']);$this->asTenant($manager,$w)->post("/task-approvals/{$approval->id}/approve")->assertRedirect();$this->assertDatabaseHas('tasks',['id'=>$task->id,'status'=>'completed']);}public function test_manager_rejection_reopens_task_and_workspace_scope_counts():void{[$m,$w]=$this->member('manager');$task=Task::create(['workspace_id'=>$w->id,'title'=>'Needs approval','priority'=>'medium','status'=>'review','approval_required'=>true]);$approval=TaskApproval::create(['workspace_id'=>$w->id,'task_id'=>$task->id,'status'=>'pending','requested_by'=>$m->id]);$this->asTenant($m,$w)->post("/task-approvals/{$approval->id}/reject",['rejection_reason'=>'Fix'])->assertRedirect();$this->assertDatabaseHas('tasks',['id'=>$task->id,'status'=>'reopened']);$this->asTenant($m,$w)->get('/manager-dashboard')->assertOk()->assertSee('Follow-up required');}public function test_missing_report_job_creates_workspace_scoped_missing_record():void{[$u,$w]=$this->member('staff');DetectMissingDailyReportsJob::dispatchSync();$this->assertDatabaseHas('missing_daily_reports',['workspace_id'=>$w->id,'user_id'=>$u->id,'status'=>'missing']);}}
